import { useState } from "react"
import "./style/login.css"
import { Form, Input, Button, Checkbox, Typography } from "antd"
import {
  UserOutlined,
  LockOutlined,
  SunOutlined,
  MoonOutlined,
  GlobalOutlined,
  CheckCircleFilled
} from "@ant-design/icons"
import { useNavigate } from "react-router-dom"
import { useTheme } from "../../shared/lib/providers/theme-provider"
import { useTranslation, Locale } from "../../shared/lib/providers/i18n-provider"
import PrimaryButton from "../../shared/components/PrimaryButton"
import { httpRequest } from "../../shared/lib/helpers/http-helper/api-helper"
import APIEndPoints, {
  APIOperations,
  APIStoredProcedures
} from "../../shared/lib/consts/api-end-points"

const { Title, Text } = Typography

const features = [
  "Real-time inventory & order tracking",
  "Multi-module HR & payroll management",
  "Advanced analytics & reporting",
  "Role-based access control"
]

export default function Login() {
  const { theme, toggleTheme } = useTheme()
  const { locale, setLocale, t } = useTranslation()
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()

  const onFinish = async (values: any) => {
    setLoading(true)
    const response = await httpRequest({
      method: "POST",
      url: APIEndPoints.login,
      operation: APIOperations.login,
      sp_name: APIStoredProcedures.aPIGeneralOperation,
      data: {
        User: values.username,
        LineData: values.password
      },
      useAuthorize: false
    })
    setLoading(false)
    if (response?.data?.State === 0) {
      navigate("/users")
    }
  }

  const toggleLanguage = () => {
    const newLocale: Locale = locale === "en" ? "ar" : "en"
    setLocale(newLocale)
  }

  return (
    <div className="login-page">
      {/* ---- Left branded panel ---- */}
      <div className="login-left">
        <div className="login-left-brand">
          <div className="login-left-logo">E</div>
          <Title className="login-left-brand-text">ERP Pro</Title>
        </div>

        <div className="login-left-body">
          <Title className="login-left-headline">
            Manage your <br /> business smarter.
          </Title>
          <Text className="login-left-desc">
            A unified enterprise platform that connects every department — from finance and HR to
            inventory and sales.
          </Text>
          <div className="login-left-features">
            {features.map((f) => (
              <div key={f} className="login-left-feature">
                <CheckCircleFilled style={{ color: "rgba(255,255,255,0.75)", fontSize: 14 }} />
                <span>{f}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="login-left-footer">© 2025 ERP Pro · Enterprise Edition v1.0</div>
      </div>

      {/* ---- Right form panel ---- */}
      <div className="login-right">
        <div className="login-right-inner">
          <div className="login-right-header">
            <Title level={3} className="login-right-title">
              {t("signIn") || "Sign in to your account"}
            </Title>
            <Text className="login-right-subtitle">{t("signInSubtitle")}</Text>
            <div className="login-controls">
              <Button
                size="small"
                className="login-ctrl-btn"
                icon={theme === "dark" ? <SunOutlined /> : <MoonOutlined />}
                onClick={toggleTheme}
              />
              <Button
                size="small"
                className="login-ctrl-btn"
                icon={<GlobalOutlined />}
                onClick={toggleLanguage}>
                {locale === "en" ? "EN" : "AR"}
              </Button>
            </div>
          </div>

          <Form
            name="login"
            onFinish={onFinish}
            initialValues={{ remember: true }}
            layout="vertical"
            requiredMark={false}
            className="login-form">
            <Form.Item
              name="username"
              label={t("username")}
              className="login-form-item"
              rules={[{ required: true, message: t("usernameRequired") }]}>
              <Input
                prefix={<UserOutlined className="login-input-prefix" />}
                placeholder={t("username")}
                className="login-input"
              />
            </Form.Item>

            <Form.Item
              name="password"
              label={t("password")}
              className="login-form-item"
              rules={[
                { required: true, message: t("passwordRequired") },
                { min: 6, message: t("passwordMin") }
              ]}>
              <Input.Password
                prefix={<LockOutlined className="login-input-prefix" />}
                placeholder={t("password")}
                className="login-input"
              />
            </Form.Item>

            <Form.Item className="login-footer-item">
              <div className="login-footer">
                <Form.Item name="remember" valuePropName="checked" noStyle>
                  <Checkbox>
                    <Text style={{ fontSize: 13 }}>{t("rememberMe")}</Text>
                  </Checkbox>
                </Form.Item>
                <Typography.Link style={{ fontSize: 13 }}>Forgot password?</Typography.Link>
              </div>
            </Form.Item>

            <Form.Item className="login-submit-wrapper">
              <PrimaryButton
                htmlType="submit"
                loading={loading}
                block
                className="login-submit-button">
                {t("login")}
              </PrimaryButton>
            </Form.Item>
          </Form>
        </div>
      </div>
    </div>
  )
}
